91	\title{Reply to \\ Comment on ``Multiparty quantum mutual information: An
92	alternative definition''}
93	
94	 
95	\author{Asutosh Kumar}
96	\email{asutoshk.phys@gmail.com}
97	
98	%\affiliation{Vaidic and Modern Physics Research Centre, Bhagal Bhim, Bhinmal, Jalore 343029, India}
